function acymSetCallouts(){const t=document.getElementsByClassName("acym_callout");for(let e=0;e<t.length;e++){const a=t[e],n=a.getElementsByClassName("acym_callout_close")[0];acymDisplayCallout(a,e),n.onclick=function(t){acymCloseCallout(t.target.closest(".acym_callout"))}}}function acymCloseCallout(t){t.style["margin-left"]="640px",t.style["margin-right"]="-640px",setTimeout(function(){t.remove()},1e3)}function acymDisplayCallout(t,e){setTimeout(function(){t.style["margin-left"]="0px",t.style["margin-right"]="0px"},1e3*e)}document.addEventListener("DOMContentLoaded",function(){fetch(ACYM_AJAX+"&page=acymailing_front&ctrl=frontusers&task=ajaxGetEnqueuedMessages",{method:"POST"}).then(t=>t.text()).then(t=>{try{const e=t.indexOf("{"),a=t.indexOf("[");!isNaN(e)&&e>0&&!isNaN(a)&&a>0&&(t=t.substring(e)),void 0===t&&""===t||(t=JSON.parse(t))}catch(t){console.log(t.stack)}if(!t||!t.data||!t.data.messages||0===t.data.messages.length)return;const e=document.createElement("div");for(e.innerHTML=t.data.messages;e.children.length>0;)document.body.appendChild(e.children[0]);acymSetCallouts()}).catch(t=>console.log(t.stack))});